import sys

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def isSameTree(self, root1: TreeNode, root2: TreeNode) -> bool:
        if not root1 and not root2:
            return True
        if not root1 or not root2:
            return False
        return (root1.val == root2.val and 
                self.isSameTree(root1.left, root2.left) and 
                self.isSameTree(root1.right, root2.right))

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n1 = int(next(it))
        root1 = None
        stack1 = []
        for _ in range(n1):
            val = int(next(it))
            node = TreeNode(val)
            if root1 is None:
                root1 = node
            else:
                parent = stack1.pop()
                if parent.left is None:
                    parent.left = node
                else:
                    parent.right = node
            stack1.append(node)

        n2 = int(next(it))
        root2 = None
        stack2 = []
        for _ in range(n2):
            val = int(next(it))
            node = TreeNode(val)
            if root2 is None:
                root2 = node
            else:
                parent = stack2.pop()
                if parent.left is None:
                    parent.left = node
                else:
                    parent.right = node
            stack2.append(node)

    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.isSameTree(root1, root2)
    print(str(ans).lower())

