#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    bool isSameTree(TreeNode* root1, TreeNode* root2) {
        if (!root1 && !root2) return true;
        if (!root1 || !root2) return false;
        return (root1->val == root2->val && 
                isSameTree(root1->left, root2->left) && 
                isSameTree(root1->right, root2->right));
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n1;
    cin >> n1;
    TreeNode* root1 = nullptr;
    stack<TreeNode*> stack1;
    for (int i = 0; i < n1; i++) {
        int val;
        cin >> val;
        TreeNode* node = new TreeNode(val);
        if (root1 == nullptr) {
            root1 = node;
        } else {
            TreeNode* parent = stack1.top();
            stack1.pop();
            if (parent->left == nullptr) {
                parent->left = node;
            } else {
                parent->right = node;
            }
        }
        stack1.push(node);
    }

    int n2;
    cin >> n2;
    TreeNode* root2 = nullptr;
    stack<TreeNode*> stack2;
    for (int i = 0; i < n2; i++) {
        int val;
        cin >> val;
        TreeNode* node = new TreeNode(val);
        if (root2 == nullptr) {
            root2 = node;
        } else {
            TreeNode* parent = stack2.top();
            stack2.pop();
            if (parent->left == nullptr) {
                parent->left = node;
            } else {
                parent->right = node;
            }
        }
        stack2.push(node);
    }

    Solution sol;
    bool ans = sol.isSameTree(root1, root2);
    cout << (ans ? "true" : "false") << endl;
    return 0;
}
